// ── Lahiri Ayanamsa — বিশুদ্ধ সিদ্ধান্ত পঞ্জিকা মাসওয়ারি মান ──
// [JD_start, ayanamsa_degrees]
const _AY_TBL=[
  [2460780.5,24.21027778],
  [2460811.5,24.21166667],
  [2460842.5,24.21333333],
  [2460873.5,24.21527778],
  [2460905.5,24.21638889],
  [2460936.5,24.21722222],
  [2460966.5,24.21833333],
  [2460997.5,24.21944444],
  [2461026.5,24.22083333],
  [2461055.5,24.2225],
  [2461084.5,24.22416667],
  [2461113.5,24.225],
  [2461145.5,24.22583333],
  [2461176.5,24.22694444],
  [2461206.5,24.22861111],
  [2461237.5,24.23],
  [2461268.5,24.23166667],
  [2461299.5,24.23277778],
  [2461330.5,24.23388889],
  [2461361.5,24.235],
  [2461391.5,24.23638889],
  [2461420.5,24.23805556],
  [2461449.5,24.23916667],
  [2461478.5,24.24027778],
];
function _lahiriAY(jd){
  for(var i=_AY_TBL.length-1;i>=0;i--){if(jd>=_AY_TBL[i][0])return _AY_TBL[i][1];}
  return _AY_TBL[0][1];
}

// ── JPL টেবিল থেকে গ্রহ অবস্থান (linear interpolation) ──
function _jplGet(tbl,jd){
  var h=Math.round((jd-_EPH_JDB)*24*10)/10; // fractional hours
  var hh=(jd-_EPH_JDB)*24;
  var n=tbl.length;
  if(hh<=tbl[0])return tbl[1]/100;
  if(hh>=tbl[n-2])return tbl[n-1]/100;
  for(var i=0;i<n-2;i+=2){
    if(tbl[i]<=hh&&hh<tbl[i+2]){
      var f=(hh-tbl[i])/(tbl[i+2]-tbl[i]);
      var d=(tbl[i+3]-tbl[i+1])/100;
      if(d>180)d-=360; if(d<-180)d+=360;
      return((tbl[i+1]/100+f*d)%360+360)%360;
    }
  }
  return tbl[1]/100;
}

// ── সিদ্ধান্তীয় (নিরয়ণ) গ্রহ অবস্থান — JPL DE441 ভিত্তিক ──
function jplSunSid(jd){return(_jplGet(_E_SUN,jd)-_lahiriAY(jd)+360)%360;}
function jplMarsSid(jd){return(_jplGet(_E_MARS,jd)-_lahiriAY(jd)+360)%360;}
function jplJupSid(jd){return(_jplGet(_E_JUP,jd)-_lahiriAY(jd)+360)%360;}
function jplSatSid(jd){return(_jplGet(_E_SAT,jd)-_lahiriAY(jd)+360)%360;}
function jplVenSid(jd){return(_jplGet(_E_VEN,jd)-_lahiriAY(jd)+360)%360;}
function jplMerSid(jd){return(_jplGet(_E_MER,jd)-_lahiriAY(jd)+360)%360;}

// ── সূর্যোদয়/অস্ত গণনা (h0=0°, সূর্য সিদ্ধান্ত পদ্ধতি) ──
// JPL-ভিত্তিক সূর্যের সঠিক অবনমন ব্যবহার করে
function jplSunTimes(y,m,d){
  var jd0=JD(y,m,d);
  var n=jd0-2451545+0.5-LNG/360;
  // JPL tropical longitude at local noon
  var jdNoon=jd0+(12-TZ)/24;
  var sunTrop=_jplGet(_E_SUN,jdNoon);
  var eps=23.439291*Math.PI/180;
  var lamR=sunTrop*Math.PI/180;
  var sinDec=Math.sin(eps)*Math.sin(lamR);
  var dec=Math.asin(sinDec);
  var e2=0.016708634,y2=Math.tan(eps/2)**2,lR=sunTrop*Math.PI/180;
  var EoT=4*(y2*Math.sin(2*lR)-2*e2*Math.sin(((357.52911+0.9856003*n)%360+360)*Math.PI/180))*(180/Math.PI);
  var latR=LAT*Math.PI/180;
  var cosH=(-Math.sin(latR)*sinDec)/(Math.cos(latR)*Math.cos(dec));
  if(Math.abs(cosH)>1)return{rise:6,set:18};
  var H=Math.acos(Math.min(1,Math.max(-1,cosH)))*180/Math.PI;
  var noon=(720-4*LNG-EoT)/60+TZ;
  return{rise:noon-H/15,set:noon+H/15};
}
